import LocalAuthentication

class AuthenticationManager {
    static var isAuthenticated = false
    
    func authenticate() -> Bool {
        let context = LAContext()
        var error: NSError?
        
        if context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) {
            let reason = "Please authenticate to access the app"
            
            return context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, evaluateError in
                if success {
                    isAuthenticated = true
                    print("User authenticated successfully")
                } else {
                    print("User authentication failed")
                }
            }
        } else {
            print("Biometric authentication not available on this device")
            return false
        }
    }
    
    func bypassLogin() -> Bool {
        if isAuthenticated {
            return true
        } else {
            return false
        }
    }
